using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketService
{
    private readonly EventDbContext _context;

    public TicketService(EventDbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
    {
        using (var transaction = await _context.Database.BeginTransactionAsync())
        {
            try
            {
                var eventEntity = await _context.Events
                    .Where(e => e.Id == eventId)
                    .SingleOrDefaultAsync();

                if (eventEntity == null || eventEntity.AvailableSeats < quantity)
                {
                    return false; // Event not found or not enough seats
                }

                eventEntity.AvailableSeats -= quantity;

                var purchase = new TicketPurchase
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    PurchaseDate = DateTime.UtcNow
                };

                _context.TicketPurchases.Add(purchase);

                await _context.SaveChangesAsync();
                await transaction.CommitAsync();

                return true;
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
                return false;
            }
        }
    }
}

